# economic_graphrag/vector_store/simple_vector_store.py
# Lightweight JSON-backed vector store using numpy cosine similarity.
# Drop-in replacement for ChromaVectorStore when chromadb is unavailable.

import json
import math
import os
from pathlib import Path
from typing import Any, Dict, List, Tuple

import numpy as np

from economic_graphrag.config import settings
from economic_graphrag.vector_store.base import BaseVectorStore


def _cosine_similarity(a: List[float], b: List[float]) -> float:
    a, b = np.array(a, dtype=float), np.array(b, dtype=float)
    norm_a, norm_b = np.linalg.norm(a), np.linalg.norm(b)
    if norm_a == 0 or norm_b == 0:
        return 0.0
    return float(np.dot(a, b) / (norm_a * norm_b))


class SimpleVectorStore(BaseVectorStore):
    """
    A lightweight JSON-backed vector store using numpy cosine similarity.
    Falls back to keyword matching when embeddings are unavailable.
    """

    def __init__(
        self,
        path: str = settings.CHROMA_PATH,
        collection_name: str = settings.CHROMA_COLLECTION_NAME,
    ):
        self.db_path = Path(path) / f"{collection_name}.json"
        self.db_path.parent.mkdir(parents=True, exist_ok=True)
        self._data: List[Dict[str, Any]] = []
        self._load()

    def _load(self):
        if self.db_path.exists():
            try:
                with open(self.db_path) as f:
                    self._data = json.load(f)
            except Exception:
                self._data = []

    def _save(self):
        with open(self.db_path, "w") as f:
            json.dump(self._data, f)

    def _get_embedder(self):
        try:
            from economic_graphrag.embeddings.embedder import embedder
            return embedder
        except Exception:
            return None

    def add_documents(self, chunks: List[Dict[str, Any]]):
        if not chunks:
            return
        embedder = self._get_embedder()
        existing_ids = {item["chunk_id"] for item in self._data}
        new_chunks = [c for c in chunks if c.get("chunk_id") not in existing_ids]
        if not new_chunks:
            return
        contents = [c["content"] for c in new_chunks]
        embeddings = None
        if embedder:
            try:
                embeddings = embedder.embed_documents(contents)
            except Exception:
                pass
        for i, chunk in enumerate(new_chunks):
            record = {k: v for k, v in chunk.items()}
            if embeddings:
                record["_embedding"] = embeddings[i]
            self._data.append(record)
        self._save()
        print(f"Added {len(new_chunks)} documents to SimpleVectorStore.")

    def _keyword_score(self, query: str, content: str) -> float:
        query_words = set(query.lower().split())
        content_words = set(content.lower().split())
        if not query_words:
            return 0.0
        return len(query_words & content_words) / len(query_words)

    def similarity_search(
        self, query: str, top_k: int = 5
    ) -> List[Tuple[Dict[str, Any], float]]:
        if not self._data:
            return []

        embedder = self._get_embedder()
        use_embeddings = bool(embedder and self._data and "_embedding" in self._data[0])

        if use_embeddings:
            try:
                query_emb = embedder.embed_query(query)
                scored = [
                    (item, _cosine_similarity(query_emb, item["_embedding"]))
                    for item in self._data
                    if "_embedding" in item
                ]
            except Exception:
                use_embeddings = False

        if not use_embeddings:
            scored = [
                (item, self._keyword_score(query, item.get("content", "")))
                for item in self._data
            ]

        scored.sort(key=lambda x: x[1], reverse=True)
        results = []
        for item, score in scored[:top_k]:
            chunk = {k: v for k, v in item.items() if k != "_embedding"}
            results.append((chunk, score))
        return results

    def metadata_filtered_search(
        self, query: str, filter_metadata: Dict[str, Any], top_k: int = 5
    ) -> List[Tuple[Dict[str, Any], float]]:
        filtered = [
            item
            for item in self._data
            if all(item.get(k) == v for k, v in filter_metadata.items())
        ]
        if not filtered:
            return []
        tmp_store = SimpleVectorStore.__new__(SimpleVectorStore)
        tmp_store._data = filtered
        tmp_store.db_path = self.db_path
        return tmp_store.similarity_search(query, top_k)

    def get_collection_size(self) -> int:
        return len(self._data)

# economic_graphrag/embeddings/embedder.py
from typing import List

import numpy as np

from economic_graphrag.config import settings


class Embedder:
    """
    Embedding model wrapper. Tries sentence-transformers first;
    falls back to a simple TF-IDF-style bag-of-words representation
    so the app runs even when the model cannot be downloaded.
    """

    _instance = None
    _model = None
    _mode = "unavailable"

    def __new__(cls):
        if cls._instance is None:
            cls._instance = super().__new__(cls)
            cls._instance._init_model()
        return cls._instance

    def _init_model(self):
        try:
            from sentence_transformers import SentenceTransformer
            self._model = SentenceTransformer(settings.EMBEDDING_MODEL_NAME)
            self._mode = "sentence_transformers"
            print(f"Embedding model '{settings.EMBEDDING_MODEL_NAME}' loaded.")
        except Exception as e:
            print(f"sentence-transformers unavailable ({e}). Using keyword fallback.")
            self._model = None
            self._mode = "keyword_fallback"

    # ------------------------------------------------------------------
    # Keyword-fallback: simple normalised bag-of-words vector
    # ------------------------------------------------------------------
    _vocab: dict = {}

    def _bow(self, text: str) -> List[float]:
        words = text.lower().split()
        freq: dict = {}
        for w in words:
            if w not in self._vocab:
                self._vocab[w] = len(self._vocab)
            freq[self._vocab[w]] = freq.get(self._vocab[w], 0) + 1
        dim = len(self._vocab)
        vec = [0.0] * dim
        for idx, count in freq.items():
            if idx < dim:
                vec[idx] = count
        norm = np.linalg.norm(vec)
        return [v / norm for v in vec] if norm > 0 else vec

    def _pad(self, vecs: List[List[float]]) -> List[List[float]]:
        if not vecs:
            return vecs
        dim = max(len(v) for v in vecs)
        return [v + [0.0] * (dim - len(v)) for v in vecs]

    # ------------------------------------------------------------------

    def embed_documents(self, texts: List[str]) -> List[List[float]]:
        if self._mode == "sentence_transformers":
            return self._model.encode(texts, convert_to_numpy=True).tolist()
        vecs = [self._bow(t) for t in texts]
        return self._pad(vecs)

    def embed_query(self, query: str) -> List[float]:
        if self._mode == "sentence_transformers":
            return self._model.encode(query, convert_to_numpy=True).tolist()
        vec = self._bow(query)
        dim = len(self._vocab)
        return vec + [0.0] * (dim - len(vec))


embedder = Embedder()

# economic_graphrag/vector_store/chroma_manager.py
# Tries to import chromadb; if unavailable, transparently falls back
# to the lightweight SimpleVectorStore implementation.

from typing import Any, Dict, List, Tuple

from economic_graphrag.config import settings
from economic_graphrag.vector_store.base import BaseVectorStore


def _build_store() -> BaseVectorStore:
    try:
        import chromadb
        from economic_graphrag.embeddings.embedder import embedder

        class _ChromaVectorStore(BaseVectorStore):
            def __init__(self):
                self.client = chromadb.PersistentClient(path=settings.CHROMA_PATH)
                self.collection = self.client.get_or_create_collection(
                    name=settings.CHROMA_COLLECTION_NAME
                )

            def add_documents(self, chunks: List[Dict[str, Any]]):
                if not chunks:
                    return
                ids = [c["chunk_id"] for c in chunks]
                contents = [c["content"] for c in chunks]
                embeddings = embedder.embed_documents(contents)
                metadatas = [
                    {k: v for k, v in c.items() if k != "content" and isinstance(v, (str, int, float, bool))}
                    for c in chunks
                ]
                self.collection.add(
                    embeddings=embeddings,
                    documents=contents,
                    metadatas=metadatas,
                    ids=ids,
                )

            def _format(self, results) -> List[Tuple[Dict[str, Any], float]]:
                out = []
                if not results or not results.get("ids"):
                    return out
                for i in range(len(results["ids"][0])):
                    chunk = results["metadatas"][0][i]
                    chunk["content"] = results["documents"][0][i]
                    score = 1 - results["distances"][0][i]
                    out.append((chunk, score))
                return out

            def similarity_search(self, query: str, top_k: int = 5):
                qe = embedder.embed_query(query)
                return self._format(self.collection.query(query_embeddings=[qe], n_results=top_k))

            def metadata_filtered_search(self, query: str, filter_metadata: Dict[str, Any], top_k: int = 5):
                qe = embedder.embed_query(query)
                return self._format(
                    self.collection.query(query_embeddings=[qe], n_results=top_k, where=filter_metadata)
                )

            def get_collection_size(self) -> int:
                return self.collection.count()

        print("Using ChromaDB vector store.")
        return _ChromaVectorStore()
    except ImportError:
        from economic_graphrag.vector_store.simple_vector_store import SimpleVectorStore
        print("chromadb not available — using SimpleVectorStore fallback.")
        return SimpleVectorStore()


class ChromaVectorStore(BaseVectorStore):
    """
    Public API: delegates to chromadb if available, otherwise SimpleVectorStore.
    """

    def __init__(self, path: str = settings.CHROMA_PATH, collection_name: str = settings.CHROMA_COLLECTION_NAME):
        self._store = _build_store()

    def add_documents(self, chunks: List[Dict[str, Any]]):
        return self._store.add_documents(chunks)

    def similarity_search(self, query: str, top_k: int = 5) -> List[Tuple[Dict[str, Any], float]]:
        return self._store.similarity_search(query, top_k)

    def metadata_filtered_search(self, query: str, filter_metadata: Dict[str, Any], top_k: int = 5) -> List[Tuple[Dict[str, Any], float]]:
        return self._store.metadata_filtered_search(query, filter_metadata, top_k)

    def get_collection_size(self) -> int:
        return self._store.get_collection_size()

# economic_graphrag/graph/neo4j_manager.py
from typing import List, Dict, Any

from economic_graphrag.config import settings


class Neo4jManager:
    """
    Manages the connection to a Neo4j database.
    Degrades gracefully when Neo4j is not available.
    """

    _instance = None
    _driver = None

    def __new__(cls):
        if cls._instance is None:
            cls._instance = super().__new__(cls)
            cls._instance._connect()
        return cls._instance

    def _connect(self):
        try:
            from neo4j import GraphDatabase, basic_auth
            self._driver = GraphDatabase.driver(
                settings.NEO4J_URI,
                auth=basic_auth(settings.NEO4J_USER, settings.NEO4J_PASSWORD),
                connection_timeout=5,
            )
            self._driver.verify_connectivity()
            print("Neo4j connection successful.")
        except Exception as e:
            print(f"Neo4j not available (will return empty results): {e}")
            self._driver = None

    @property
    def available(self) -> bool:
        return self._driver is not None

    def close(self):
        if self._driver is not None:
            self._driver.close()
            print("Neo4j connection closed.")

    def execute_query(self, query: str, parameters: Dict[str, Any] = None) -> List[Dict[str, Any]]:
        if self._driver is None:
            return []
        try:
            with self._driver.session() as session:
                result = session.run(query, parameters or {})
                return [record.data() for record in result]
        except Exception as e:
            print(f"Neo4j query error: {e}")
            return []

    def execute_write(self, query: str, parameters: Dict[str, Any] = None):
        if self._driver is None:
            return
        try:
            with self._driver.session() as session:
                session.write_transaction(self._run_transaction, query, parameters or {})
        except Exception as e:
            print(f"Neo4j write error: {e}")

    @staticmethod
    def _run_transaction(tx, query, parameters):
        tx.run(query, parameters)

    def create_constraints(self):
        if self._driver is None:
            return
        constraints = {
            "Country": "name",
            "Indicator": "name",
            "Report": "id",
            "Source": "name",
            "EconomicConcept": "name",
            "Institution": "name",
            "Region": "name",
            "Forecast": "id",
        }
        for label, prop in constraints.items():
            q = f"CREATE CONSTRAINT IF NOT EXISTS FOR (n:{label}) REQUIRE n.{prop} IS UNIQUE"
            try:
                self.execute_write(q)
            except Exception as e:
                print(f"Constraint error for {label}: {e}")


neo4j_manager = Neo4jManager()

# economic_graphrag/agents/answer_agent.py
from typing import Dict, Any

from economic_graphrag.llm.gemini_client import GeminiClient
from economic_graphrag.llm.json_utils import LLMJSONParseError, parse_json_object


class AnswerAgent:
    """
    An agent responsible for synthesizing a final answer from retrieved context.
    """

    def __init__(self):
        self.llm_client = GeminiClient()

    def generate_answer(self, query: str, context: Dict[str, Any]) -> Dict[str, Any]:
        vector_results = context.get("vector_results", [])
        graph_results = context.get("graph_results", [])

        vector_context_str = "\n".join(
            [f"- {r.get('content', str(r))}" for r in vector_results[:5]]
        ) or "No vector context available."

        graph_context_str = "\n".join(
            [str(r) for r in graph_results[:5]]
        ) or "No graph context available."

        prompt = f"""
You are a macroeconomic expert. Answer the user's question using the provided context.

User Question: "{query}"

Vector Search Context (relevant document chunks):
{vector_context_str}

Graph Search Context (entity relationships):
{graph_context_str}

Provide a comprehensive, accurate answer. If the context is insufficient, say so.

Respond ONLY with a valid JSON object with these fields:
- "answer": the main answer (string)
- "sources": list of source references (list of strings, can be empty)
- "explainability": brief note on what sources/context were used (string)

Example:
{{
  "answer": "GDP measures the total monetary value...",
  "sources": ["World Bank", "IMF Report 2023"],
  "explainability": "Answer derived from vector search results about GDP definitions."
}}
"""
        default = {
            "answer": "I was unable to generate an answer. Please check that the Gemini API key is configured.",
            "sources": [],
            "explainability": "LLM call failed.",
        }

        response = self.llm_client.generate(prompt, format="json")

        if "error" in response or "response" not in response:
            print(f"Answer agent LLM error: {response.get('error', 'no response')}")
            return default

        try:
            result = parse_json_object(response["response"])
            return {
                "answer": result.get("answer", default["answer"]),
                "sources": result.get("sources", []),
                "explainability": result.get("explainability", ""),
            }
        except (LLMJSONParseError, Exception) as e:
            print(f"Answer agent JSON parse error: {e}")
            raw = response.get("response", "")
            return {
                "answer": raw if raw else default["answer"],
                "sources": [],
                "explainability": "Raw LLM response used (JSON parse failed).",
            }

