# economic_graphrag/llm/openrouter_client.py
import os
from typing import Any, Dict

import requests

from economic_graphrag.llm.json_utils import _strip_json_fences

FREE_MODELS = [
    "deepseek/deepseek-r1-0528:free",
    "meta-llama/llama-4-scout:free",
    "google/gemma-3-27b-it:free",
    "microsoft/phi-4-reasoning:free",
    "deepseek/deepseek-chat-v3-0324:free",
]


class OpenRouterClient:
    """
    Client for OpenRouter API (free models).
    """

    ENDPOINT = "https://openrouter.ai/api/v1/chat/completions"

    def __init__(self):
        self.api_key = os.getenv("OPENROUTER_API_KEY", "")
        if not self.api_key:
            print("WARNING: OPENROUTER_API_KEY is not set.")

    def generate(self, prompt: str, format: str = "json") -> Dict[str, Any]:
        if not self.api_key:
            return {"error": "OPENROUTER_API_KEY not configured"}

        system = (
            "You are a helpful macroeconomic expert. "
            + ("Always respond with valid JSON only, no extra text." if format == "json" else "")
        )

        for model in FREE_MODELS:
            try:
                response = requests.post(
                    self.ENDPOINT,
                    headers={
                        "Authorization": f"Bearer {self.api_key}",
                        "Content-Type": "application/json",
                        "HTTP-Referer": "https://replit.com",
                        "X-Title": "Economic GraphRAG",
                    },
                    json={
                        "model": model,
                        "messages": [
                            {"role": "system", "content": system},
                            {"role": "user", "content": prompt},
                        ],
                        "temperature": 0.1,
                    },
                    timeout=45,
                )
            except requests.exceptions.RequestException as exc:
                print(f"OpenRouter request error ({model}): {exc}")
                continue

            if response.status_code != 200:
                err = response.text[:200]
                print(f"OpenRouter {model} error {response.status_code}: {err}")
                continue

            try:
                data = response.json()
                content = data["choices"][0]["message"]["content"]
                if format == "json":
                    content = _strip_json_fences(content)
                return {"response": content}
            except (KeyError, IndexError, ValueError) as exc:
                print(f"OpenRouter parse error ({model}): {exc}")
                continue

        return {"error": "All OpenRouter models failed"}

# economic_graphrag/llm/llm_factory.py
import os
from typing import Any, Dict


def get_llm_client():
    """
    Returns the best available LLM client.
    Prefers Gemini if GEMINI_API_KEY is set, otherwise OpenRouter.
    """
    gemini_key = os.getenv("GEMINI_API_KEY", "")
    openrouter_key = os.getenv("OPENROUTER_API_KEY", "")

    if gemini_key:
        from economic_graphrag.llm.gemini_client import GeminiClient
        return GeminiClient()
    elif openrouter_key:
        from economic_graphrag.llm.openrouter_client import OpenRouterClient
        return OpenRouterClient()
    else:
        raise RuntimeError("No LLM API key configured. Set GEMINI_API_KEY or OPENROUTER_API_KEY.")


class FallbackLLMClient:
    """
    Tries Gemini first, falls back to OpenRouter.
    """

    def __init__(self):
        self._clients = []
        gemini_key = os.getenv("GEMINI_API_KEY", "")
        openrouter_key = os.getenv("OPENROUTER_API_KEY", "")
        if gemini_key:
            from economic_graphrag.llm.gemini_client import GeminiClient
            self._clients.append(GeminiClient())
        if openrouter_key:
            from economic_graphrag.llm.openrouter_client import OpenRouterClient
            self._clients.append(OpenRouterClient())
        if not self._clients:
            raise RuntimeError("No LLM API key configured.")

    def generate(self, prompt: str, format: str = "json") -> Dict[str, Any]:
        for client in self._clients:
            result = client.generate(prompt, format=format)
            if "error" not in result:
                return result
            print(f"LLM client {type(client).__name__} failed: {result.get('error')}")
        return {"error": "All LLM clients failed"}

# economic_graphrag/embeddings/embedder.py
"""
Embedding layer with three tiers:
  1. Gemini text-embedding-004 (semantic, free)
  2. sentence-transformers (if installed)
  3. TF-IDF with scikit-learn (keyword-based fallback)
"""
import os
from typing import List

import numpy as np

from economic_graphrag.config import settings


class GeminiEmbedder:
    """Uses Gemini text-embedding-004."""

    ENDPOINT = (
        "https://generativelanguage.googleapis.com/v1beta/"
        "models/text-embedding-004:embedContent"
    )
    DIM = 768

    def __init__(self, api_key: str):
        self.api_key = api_key

    def embed_one(self, text: str) -> List[float]:
        import requests
        resp = requests.post(
            self.ENDPOINT,
            headers={"Content-Type": "application/json",
                     "x-goog-api-key": self.api_key},
            json={"model": "models/text-embedding-004",
                  "content": {"parts": [{"text": text[:8000]}]}},
            timeout=20,
        )
        resp.raise_for_status()
        return resp.json()["embedding"]["values"]

    def embed_documents(self, texts: List[str]) -> List[List[float]]:
        results = []
        for t in texts:
            try:
                results.append(self.embed_one(t))
            except Exception as e:
                print(f"Gemini embed error: {e}")
                results.append([0.0] * self.DIM)
        return results

    def embed_query(self, query: str) -> List[float]:
        try:
            return self.embed_one(query)
        except Exception as e:
            print(f"Gemini embed error: {e}")
            return [0.0] * self.DIM


class TFIDFEmbedder:
    """TF-IDF based embedder using scikit-learn. Fits lazily."""

    def __init__(self):
        from sklearn.feature_extraction.text import TfidfVectorizer
        self._vectorizer = TfidfVectorizer(max_features=1024, sublinear_tf=True)
        self._fitted = False
        self._corpus: List[str] = []

    def _fit_if_needed(self, texts: List[str]):
        all_texts = self._corpus + [t for t in texts if t not in self._corpus]
        self._corpus = all_texts
        if len(all_texts) >= 1:
            self._vectorizer.fit(all_texts)
            self._fitted = True

    def embed_documents(self, texts: List[str]) -> List[List[float]]:
        self._fit_if_needed(texts)
        mat = self._vectorizer.transform(texts).toarray()
        norms = np.linalg.norm(mat, axis=1, keepdims=True)
        norms[norms == 0] = 1
        return (mat / norms).tolist()

    def embed_query(self, query: str) -> List[float]:
        if not self._fitted:
            self._fit_if_needed([query])
        vec = self._vectorizer.transform([query]).toarray()[0]
        norm = np.linalg.norm(vec)
        return (vec / norm).tolist() if norm > 0 else vec.tolist()


class Embedder:
    """
    Singleton embedder. Priority: Gemini API → sentence-transformers → TF-IDF.
    """

    _instance = None

    def __new__(cls):
        if cls._instance is None:
            cls._instance = super().__new__(cls)
            cls._instance._init()
        return cls._instance

    def _init(self):
        self._backend = None
        self._mode = "none"

        # Tier 1: Gemini embedding API
        gemini_key = os.getenv("GEMINI_API_KEY", "")
        if gemini_key:
            try:
                ge = GeminiEmbedder(gemini_key)
                ge.embed_one("test")
                self._backend = ge
                self._mode = "gemini"
                print("Embedder: using Gemini text-embedding-004")
                return
            except Exception as e:
                print(f"Embedder: Gemini unavailable ({e}), trying next...")

        # Tier 2: sentence-transformers
        try:
            from sentence_transformers import SentenceTransformer
            model = SentenceTransformer(settings.EMBEDDING_MODEL_NAME)

            class _STBackend:
                def __init__(self, m): self.m = m
                def embed_documents(self, texts): return self.m.encode(texts, convert_to_numpy=True).tolist()
                def embed_query(self, q): return self.m.encode(q, convert_to_numpy=True).tolist()

            self._backend = _STBackend(model)
            self._mode = "sentence_transformers"
            print(f"Embedder: using sentence-transformers ({settings.EMBEDDING_MODEL_NAME})")
            return
        except Exception as e:
            print(f"Embedder: sentence-transformers unavailable ({e}), falling back to TF-IDF")

        # Tier 3: TF-IDF
        self._backend = TFIDFEmbedder()
        self._mode = "tfidf"
        print("Embedder: using TF-IDF (scikit-learn)")

    def embed_documents(self, texts: List[str]) -> List[List[float]]:
        return self._backend.embed_documents(texts)

    def embed_query(self, query: str) -> List[float]:
        return self._backend.embed_query(query)

    @property
    def mode(self) -> str:
        return self._mode


embedder = Embedder()

