"""
Entity and relationship extractor.
Uses spaCy NER (if model is available) + LLM for structured extraction.
"""
from typing import Any, Dict, List, Set

from economic_graphrag.llm.llm_factory import FallbackLLMClient
from economic_graphrag.llm.json_utils import LLMJSONParseError, parse_json_object

# Try loading spaCy model
_nlp = None
try:
    import spacy
    _nlp = spacy.load("en_core_web_sm")
    print("spaCy en_core_web_sm loaded for entity extraction.")
except Exception as e:
    print(f"spaCy model not available ({e}); using LLM-only extraction.")


class EntityExtractor:
    """
    Extracts entities and relationships from text using spaCy + LLM.
    """

    def __init__(self):
        self.llm_client = FallbackLLMClient()

    # ------------------------------------------------------------------
    def extract_entities_spacy(self, text: str) -> Dict[str, Set[str]]:
        entities: Dict[str, Set[str]] = {"Country": set(), "Institution": set(), "Region": set()}
        if _nlp is None:
            return entities
        doc = _nlp(text[:5000])
        for ent in doc.ents:
            if ent.label_ in ("GPE", "LOC"):
                entities["Country"].add(ent.text.strip())
            elif ent.label_ == "ORG":
                entities["Institution"].add(ent.text.strip())
            elif ent.label_ == "NORP":
                entities["Region"].add(ent.text.strip())
        return entities

    # ------------------------------------------------------------------
    def extract_with_llm(self, chunk_content: str) -> Dict[str, Any]:
        prompt = f"""
From the following economic text, extract entities and relationships.

Respond ONLY with a valid JSON object with exactly two keys:
- "entities": a dict where keys are one of ["Indicator","EconomicConcept","Country","Institution","Report","Source","Forecast","Region"] and values are lists of strings (entity names).
- "relationships": a list of 3-element lists [subject, relationship_type, object].
  Allowed relationship_types: HAS_INDICATOR, CORRELATES_WITH, AFFECTS, PUBLISHED_BY, REPORTED_IN, BELONGS_TO, FORECASTS, DERIVED_FROM, HAS_TREND, INFLUENCES.

Keep entities short (2-5 words). Extract only clear, factual relationships.

Text (first 1500 chars): "{chunk_content[:1500]}"

Example:
{{
  "entities": {{
    "Indicator": ["GDP", "inflation rate"],
    "Country": ["United States"],
    "EconomicConcept": ["economic growth"]
  }},
  "relationships": [
    ["inflation rate", "AFFECTS", "economic growth"],
    ["United States", "HAS_INDICATOR", "GDP"]
  ]
}}
"""
        response = self.llm_client.generate(prompt, format="json")

        if "error" in response or "response" not in response:
            return {"entities": {}, "relationships": []}

        try:
            result = parse_json_object(response["response"])
            if "entities" not in result or "relationships" not in result:
                return {"entities": {}, "relationships": []}
            return result
        except LLMJSONParseError:
            return {"entities": {}, "relationships": []}

    # ------------------------------------------------------------------
    def extract_all(self, chunk: Dict[str, Any]) -> Dict[str, Any]:
        """
        Combines spaCy NER + LLM extraction + chunk metadata.
        """
        content = chunk.get("content", "")

        spacy_ents = self.extract_entities_spacy(content)
        llm_data = self.extract_with_llm(content)
        llm_entities: Dict[str, List[str]] = llm_data.get("entities", {})
        relationships: List[List[str]] = llm_data.get("relationships", [])

        all_entities: Dict[str, Set[str]] = {
            "Country": set(), "Institution": set(), "Indicator": set(),
            "EconomicConcept": set(), "Report": set(), "Source": set(),
            "Forecast": set(), "Region": set(),
        }

        # Merge spaCy
        for k, v in spacy_ents.items():
            if k in all_entities:
                all_entities[k].update(v)

        # Merge LLM
        for etype, elist in llm_entities.items():
            if etype in all_entities and isinstance(elist, list):
                all_entities[etype].update(str(e) for e in elist)

        # Add from metadata
        if chunk.get("country"):
            all_entities["Country"].add(chunk["country"])
        if chunk.get("indicator"):
            all_entities["Indicator"].add(chunk["indicator"])
        if chunk.get("source"):
            all_entities["Source"].add(chunk["source"])
        if chunk.get("title"):
            all_entities["Report"].add(chunk["title"])

        # Validate relationships: must be [str, str, str]
        valid_rels = []
        for r in relationships:
            if isinstance(r, list) and len(r) == 3 and all(isinstance(x, str) for x in r):
                valid_rels.append(r)

        final_entities = {k: list(v) for k, v in all_entities.items() if v}
        return {"entities": final_entities, "relationships": valid_rels}

