"""
OECD data loader — uses the OECD SDMX REST API.
Fetches GDP growth rates for G7 countries.
Falls back gracefully if the API is unreachable.
"""
import uuid
from typing import Any, Dict, List

import pandas as pd
import requests

G7_COUNTRIES = {
    "CAN": "Canada", "FRA": "France", "DEU": "Germany", "ITA": "Italy",
    "JPN": "Japan", "GBR": "United Kingdom", "USA": "United States",
}

INDICATOR_NAME = "GDP growth rate (annual %, seasonally adjusted)"


def _fetch_oecd_gdp(country_code: str) -> pd.DataFrame:
    """
    Fetches annual GDP growth from OECD using the newer OECD SDMX-JSON 1.0 API.
    Falls back to World Bank if OECD fails.
    """
    # OECD SDMX-JSON endpoint for QNA (Quarterly National Accounts)
    url = (
        f"https://sdmx.oecd.org/public/rest/data/"
        f"OECD,DF_QNA,1.0/{country_code}.B1_GE.GPSA.Q"
        f"?startPeriod=2000-Q1&format=jsondata"
    )
    try:
        resp = requests.get(url, timeout=15)
        if resp.status_code == 200:
            data = resp.json()
            series_data = data.get("data", {}).get("dataSets", [{}])[0]
            obs = series_data.get("series", {})
            if obs:
                # Extract time periods from structure
                dims = data["data"]["structure"]["dimensions"]["observation"]
                time_dim = next((d for d in dims if d["id"] == "TIME_PERIOD"), None)
                times = [v["id"] for v in time_dim["values"]] if time_dim else []

                records = []
                for series_key, series_val in obs.items():
                    for obs_key, obs_val in series_val.get("observations", {}).items():
                        idx = int(obs_key)
                        if idx < len(times):
                            records.append({"date": times[idx], "value": obs_val[0]})

                if records:
                    df = pd.DataFrame(records)
                    df["value"] = pd.to_numeric(df["value"], errors="coerce")
                    return df.dropna()
    except Exception as e:
        print(f"OECD API failed for {country_code}: {e}")

    # Fallback: World Bank annual GDP growth
    try:
        wb_url = f"http://api.worldbank.org/v2/country/{country_code}/indicator/NY.GDP.MKTP.KD.ZG"
        wb_resp = requests.get(wb_url, params={"format": "json", "per_page": 100, "date": "2000:2023"}, timeout=10)
        if wb_resp.status_code == 200:
            wb_data = wb_resp.json()
            if wb_data and len(wb_data) > 1 and wb_data[1]:
                records = [
                    {"date": str(e["date"]), "value": e["value"]}
                    for e in wb_data[1] if e.get("value") is not None
                ]
                if records:
                    df = pd.DataFrame(records)
                    df["value"] = pd.to_numeric(df["value"], errors="coerce")
                    return df.dropna()
    except Exception as e:
        print(f"World Bank GDP growth fallback also failed for {country_code}: {e}")

    return pd.DataFrame()


def load_oecd_data() -> List[Dict[str, Any]]:
    all_documents = []
    for code, name in G7_COUNTRIES.items():
        print(f"  Fetching GDP growth for {name} …")
        df = _fetch_oecd_gdp(code)
        if not df.empty:
            # Recent years summary for richer content
            recent = df.sort_values("date", ascending=False).head(20)
            content = (
                f"GDP growth rate data for {name}:\n\n"
                f"{recent.to_string(index=False)}\n\n"
                f"Average GDP growth rate (all periods): {df['value'].mean():.2f}%\n"
                f"Latest period: {df.iloc[0]['date']}, value: {df.iloc[0]['value']:.2f}%"
            )
            all_documents.append({
                "document_id": str(uuid.uuid4()),
                "title": f"{INDICATOR_NAME} - {name}",
                "source": "OECD / World Bank",
                "content": content,
                "publication_date": None,
                "country": name,
                "indicator": INDICATOR_NAME,
            })
        else:
            print(f"  No data for {name}, skipping.")

    return all_documents

# economic_graphrag/vector_store/simple_vector_store.py
"""
Lightweight JSON-backed vector store using cosine similarity.
Drop-in replacement when chromadb is unavailable.
"""
import json
from pathlib import Path
from typing import Any, Dict, List, Tuple

import numpy as np

from economic_graphrag.config import settings


def _cosine(a: List[float], b: List[float]) -> float:
    av, bv = np.array(a, dtype=float), np.array(b, dtype=float)
    # Pad shorter to match length
    if len(av) < len(bv):
        av = np.pad(av, (0, len(bv) - len(av)))
    elif len(bv) < len(av):
        bv = np.pad(bv, (0, len(av) - len(bv)))
    na, nb = np.linalg.norm(av), np.linalg.norm(bv)
    if na == 0 or nb == 0:
        return 0.0
    return float(np.dot(av, bv) / (na * nb))


def _keyword_score(query: str, content: str) -> float:
    qw = set(query.lower().split())
    cw = set(content.lower().split())
    return len(qw & cw) / len(qw) if qw else 0.0


class SimpleVectorStore:
    """
    JSON-backed vector store. Embeddings are stored alongside documents.
    Supports both embedding-based and keyword-based retrieval.
    """

    def __init__(
        self,
        path: str = settings.CHROMA_PATH,
        collection_name: str = settings.CHROMA_COLLECTION_NAME,
    ):
        self.db_path = Path(path) / f"{collection_name}.json"
        self.db_path.parent.mkdir(parents=True, exist_ok=True)
        self._data: List[Dict[str, Any]] = []
        self._load()

    # ------------------------------------------------------------------
    def _load(self):
        if self.db_path.exists():
            try:
                self._data = json.loads(self.db_path.read_text())
                print(f"SimpleVectorStore: loaded {len(self._data)} records from {self.db_path}")
            except Exception as e:
                print(f"SimpleVectorStore load error ({e}); starting fresh.")
                self._data = []

    def _save(self):
        self.db_path.write_text(json.dumps(self._data))

    # ------------------------------------------------------------------
    def _get_embedder(self):
        try:
            from economic_graphrag.embeddings.embedder import embedder
            return embedder
        except Exception:
            return None

    # ------------------------------------------------------------------
    def add_documents(self, chunks: List[Dict[str, Any]]):
        if not chunks:
            return
        embedder = self._get_embedder()
        existing_ids = {item["chunk_id"] for item in self._data}
        new_chunks = [c for c in chunks if c.get("chunk_id") not in existing_ids]
        if not new_chunks:
            print(f"SimpleVectorStore: all {len(chunks)} chunks already stored.")
            return

        contents = [c["content"] for c in new_chunks]
        embeddings = None
        if embedder:
            try:
                embeddings = embedder.embed_documents(contents)
            except Exception as e:
                print(f"Embed error: {e}")

        for i, chunk in enumerate(new_chunks):
            record = dict(chunk)
            if embeddings and i < len(embeddings):
                record["_embedding"] = embeddings[i]
            self._data.append(record)

        self._save()
        print(f"SimpleVectorStore: added {len(new_chunks)} docs (total {len(self._data)}).")

    # ------------------------------------------------------------------
    def similarity_search(
        self, query: str, top_k: int = 5
    ) -> List[Tuple[Dict[str, Any], float]]:
        if not self._data:
            return []

        embedder = self._get_embedder()
        use_embeddings = bool(
            embedder and self._data and "_embedding" in self._data[0]
        )

        if use_embeddings:
            try:
                q_emb = embedder.embed_query(query)
                scored = [
                    (item, _cosine(q_emb, item["_embedding"]))
                    for item in self._data
                    if "_embedding" in item
                ]
            except Exception:
                use_embeddings = False

        if not use_embeddings:
            scored = [
                (item, _keyword_score(query, item.get("content", "")))
                for item in self._data
            ]

        scored.sort(key=lambda x: x[1], reverse=True)
        return [
            ({k: v for k, v in item.items() if k != "_embedding"}, score)
            for item, score in scored[:top_k]
        ]

    # ------------------------------------------------------------------
    def metadata_filtered_search(
        self, query: str, filter_metadata: Dict[str, Any], top_k: int = 5
    ) -> List[Tuple[Dict[str, Any], float]]:
        filtered = [
            item for item in self._data
            if all(item.get(k) == v for k, v in filter_metadata.items())
        ]
        if not filtered:
            return []
        tmp = SimpleVectorStore.__new__(SimpleVectorStore)
        tmp._data = filtered
        tmp.db_path = self.db_path
        return tmp.similarity_search(query, top_k)

    def get_collection_size(self) -> int:
        return len(self._data)

    def clear(self):
        self._data = []
        self._save()

# economic_graphrag/agents/answer_agent.py
from typing import Any, Dict, List

from economic_graphrag.llm.llm_factory import FallbackLLMClient
from economic_graphrag.llm.json_utils import LLMJSONParseError, parse_json_object


class AnswerAgent:
    """
    Synthesizes a final answer from retrieved vector chunks and graph paths.
    """

    def __init__(self):
        self.llm_client = FallbackLLMClient()

    def generate_answer(self, query: str, context: Dict[str, Any]) -> Dict[str, Any]:
        vector_results: List[Dict] = context.get("vector_results", [])
        graph_results: List[Dict] = context.get("graph_results", [])

        vector_str = self._format_vector(vector_results)
        graph_str = self._format_graph(graph_results)

        prompt = f"""
You are an expert macroeconomic analyst. Answer the user's question using ONLY the provided context.

**User Question:** {query}

**Document Context (from vector search):**
{vector_str}

**Knowledge Graph Context (entity relationships):**
{graph_str}

**Instructions:**
1. Provide a comprehensive, factual answer grounded in the context above.
2. Reference specific data points, countries, or indicators from the context.
3. If the context is insufficient, say so clearly — do NOT invent data.
4. List any relevant sources.

Respond with a valid JSON object:
{{
  "answer": "<detailed answer string>",
  "sources": ["<source 1>", "<source 2>"],
  "explainability": "<brief note on how you used the context>"
}}
"""
        default = {
            "answer": "Unable to generate an answer. Please ensure the API key is configured and data has been ingested.",
            "sources": [],
            "explainability": "LLM call failed or no context available.",
        }

        response = self.llm_client.generate(prompt, format="json")
        if "error" in response or "response" not in response:
            return default

        try:
            result = parse_json_object(response["response"])
            return {
                "answer": result.get("answer", default["answer"]),
                "sources": result.get("sources", []),
                "explainability": result.get("explainability", ""),
            }
        except LLMJSONParseError:
            raw = response.get("response", "")
            return {
                "answer": raw if raw else default["answer"],
                "sources": [],
                "explainability": "Raw LLM response (JSON parse failed).",
            }

    # ------------------------------------------------------------------
    def _format_vector(self, results: List[Dict]) -> str:
        if not results:
            return "No document context retrieved."
        lines = []
        for i, r in enumerate(results[:5], 1):
            src = r.get("source", r.get("title", "Unknown"))
            country = r.get("country", "")
            score = r.get("score", 0)
            content = r.get("content", "")[:600]
            lines.append(
                f"[{i}] Source: {src}{' | Country: ' + country if country else ''} "
                f"(relevance: {score:.2f})\n{content}"
            )
        return "\n\n".join(lines)

    def _format_graph(self, results: List[Dict]) -> str:
        if not results:
            return "No graph relationships found."
        lines = []
        for r in results[:10]:
            subj = r.get("subject", r.get("entity1", "?"))
            rel = r.get("relationship", "RELATED_TO")
            obj = r.get("object", r.get("entity2", "?"))
            lines.append(f"  ({subj}) --[{rel}]--> ({obj})")
        return "\n".join(lines)

# economic_graphrag/main_workflow.py
from typing import Any, Dict, List, TypedDict

from langgraph.graph import END, StateGraph

from economic_graphrag.agents.planner_agent import PlannerAgent
from economic_graphrag.agents.vector_agent import VectorAgent
from economic_graphrag.agents.graph_agent import GraphAgent
from economic_graphrag.agents.answer_agent import AnswerAgent
from economic_graphrag.retrieval.vector_retriever import VectorRetriever
from economic_graphrag.retrieval.graph_retriever import GraphRetriever
from economic_graphrag.vector_store.chroma_manager import ChromaVectorStore


class GraphState(TypedDict):
    query: str
    plan: Dict[str, Any]
    vector_results: List[Dict[str, Any]]
    graph_results: List[Dict[str, Any]]
    final_answer: Dict[str, Any]


class MainWorkflow:
    """
    Orchestrates the Hybrid GraphRAG pipeline via LangGraph.
    """

    def __init__(self):
        self.planner = PlannerAgent()

        vector_store = ChromaVectorStore()
        vector_retriever = VectorRetriever(vector_store)
        graph_retriever = GraphRetriever()

        self.vector_agent = VectorAgent(vector_retriever)
        self.graph_agent = GraphAgent(graph_retriever)
        self.answer_agent = AnswerAgent()

        self.graph = self._build_graph()

    def _build_graph(self):
        wf = StateGraph(GraphState)
        wf.add_node("planner", self._run_planner)
        wf.add_node("vector_retriever", self._run_vector)
        wf.add_node("graph_retriever", self._run_graph)
        wf.add_node("answer_generator", self._run_answer)

        wf.set_entry_point("planner")

        wf.add_conditional_edges(
            "planner",
            self._decide_strategy,
            {
                "vector": "vector_retriever",
                "graph": "graph_retriever",
                "hybrid": "vector_retriever",
            },
        )

        wf.add_edge("vector_retriever", "graph_retriever")
        wf.add_edge("graph_retriever", "answer_generator")
        wf.add_edge("answer_generator", END)
        return wf.compile()

    # --- Nodes ---

    def _run_planner(self, state: GraphState) -> Dict:
        plan = self.planner.plan(state["query"])
        return {"plan": plan}

    def _run_vector(self, state: GraphState) -> Dict:
        return self.vector_agent.retrieve(state)

    def _run_graph(self, state: GraphState) -> Dict:
        return self.graph_agent.retrieve(state)

    def _run_answer(self, state: GraphState) -> Dict:
        context = {
            "vector_results": state.get("vector_results", []),
            "graph_results": state.get("graph_results", []),
        }
        return {"final_answer": self.answer_agent.generate_answer(state["query"], context)}

    def _decide_strategy(self, state: GraphState) -> str:
        return state["plan"].get("retrieval_strategy", "hybrid")

    def execute(self, query: str) -> Dict[str, Any]:
        init = {
            "query": query,
            "plan": {},
            "vector_results": [],
            "graph_results": [],
            "final_answer": {},
        }
        return self.graph.invoke(init)

