# economic_graphrag/llm/openrouter_client.py
"""
OpenRouter client that tries currently available free models in order.
Model list verified 2025-06 via GET /api/v1/models (pricing.completion == "0").
"""
import os
from typing import Any, Dict

import requests

FREE_MODELS = [
    "moonshotai/kimi-k2.6:free",
    "google/gemma-4-31b-it:free",
    "google/gemma-4-26b-a4b-it:free",
    "qwen/qwen3-next-80b-a3b-instruct:free",
    "openai/gpt-oss-120b:free",
    "nvidia/nemotron-3-super-120b-a12b:free",
    "nvidia/nemotron-nano-12b-v2-vl:free",
    "liquid/lfm-2.5-1.2b-instruct:free",
    "nvidia/nemotron-3-nano-30b-a3b:free",
    "nvidia/nemotron-nano-9b-v2:free",
]

OPENROUTER_API_BASE = "https://openrouter.ai/api/v1/chat/completions"


class OpenRouterClient:
    """
    Tries FREE_MODELS in order until one succeeds.
    """

    def __init__(self, api_key: str | None = None):
        self.api_key = api_key or os.getenv("OPENROUTER_API_KEY", "")

    def generate(self, prompt: str, format: str = "text", max_tokens: int = 1024) -> Dict[str, Any]:
        if not self.api_key:
            return {"error": "OPENROUTER_API_KEY not set"}

        headers = {
            "Authorization": f"Bearer {self.api_key}",
            "HTTP-Referer": "https://economic-graphrag.replit.app",
            "X-Title": "Economic GraphRAG",
            "Content-Type": "application/json",
        }

        for model_id in FREE_MODELS:
            payload: Dict[str, Any] = {
                "model": model_id,
                "messages": [{"role": "user", "content": prompt}],
                "max_tokens": max_tokens,
                "temperature": 0.2,
            }
            if format == "json":
                payload["response_format"] = {"type": "json_object"}

            try:
                resp = requests.post(
                    OPENROUTER_API_BASE,
                    headers=headers,
                    json=payload,
                    timeout=40,
                )
                data = resp.json()

                if resp.status_code == 200 and "choices" in data:
                    text = data["choices"][0]["message"]["content"]
                    return {"response": text, "model": model_id}

                err_msg = data.get("error", {}).get("message", str(data))
                print(f"OpenRouter {model_id} error {resp.status_code}: {err_msg[:120]}")

            except Exception as e:
                print(f"OpenRouter {model_id} exception: {e}")

        return {"error": "All OpenRouter models failed"}

